import os
import shutil
import tarfile
import zipfile

def backup_directory(directory_path, format):
    """Creates compressed archive of user directory.

    Args:
        directory_path: Path to user directory.
        format: Desired compression format (tar.gz, tar.bz2, zip, 7z).
    """

    # Create archive filename based on directory name and format
    archive_filename = f"{os.path.basename(directory_path)}_{format}"

    # Create archive based on format
    if format == "tar.gz":
        with tarfile.open(archive_filename, "w:gz") as tar:
            tar.add(directory_path, arcname=os.path.basename(directory_path))
    elif format == "tar.bz2":
        with tarfile.open(archive_filename, "w:bz2") as tar:
            tar.add(directory_path, arcname=os.path.basename(directory_path))
    elif format == "zip":
        with zipfile.ZipFile(archive_filename, "w") as zip:
            zip.write(directory_path, arcname=os.path.basename(directory_path))
    # Add support for 7z archive creation here

    # Print confirmation message
    print(f"Backup created: {archive_filename}")

